mapper.select:
SELECT id as id, dealerId as dealerId, (select dealerName from dealer where id = dealerId) as dealerName, productName as productName, orderDate as orderDate, quantity as quantity, price as price, totalAmount as totalAmount, marketFee as marketFee, giftQuantity as giftQuantity, expectRate as expectRate, realRate as realRate, balanceFee as balanceFee FROM sale_order
1=1
AND id = #{id}
AND dealerId = #{dealerId}
AND productName LIKE CONCAT('%', #{productName}, '%')
AND quantity = #{quantity}
AND giftQuantity = #{giftQuantity}
ORDER BY id DESC
